{
  "verdict": "reject",
  "conceptual_groups": [
    {
      "id": "group-1",
      "summary": "The authority model is not expressed as one fully strict operative precedence chain.",
      "severity": "major",
      "findings": [
        {
          "id": "f1",
          "description": "The operative chain collapses the component review contract and the shared review contract into one numbered item, so the role never states which layer wins if inherited review semantics differ. That is not a strict precedence chain under the governing architecture.",
          "source_section": "<authority> Operative authority precedence"
        },
        {
          "id": "f2",
          "description": "The rulebook is treated only as a required file instead of an operative governance layer, even though the authority architecture splits governance across rulebook, contract, and architecture/docs, and Step 4 requires a rulebook walk before fixes. The chain is therefore incomplete.",
          "source_section": "<authority> / <steps> Step 4"
        }
      ],
      "redesign_guidance": "List each operative layer separately and in order. Keep controller/runtime authority first, then the component-local governance obligations it actually enforces, then component/shared review contracts in explicit precedence order, and keep reference docs outside that operative chain."
    },
    {
      "id": "group-2",
      "summary": "Carry-forward and arbitration mechanics are not mechanical enough to guarantee stable governed review behavior.",
      "severity": "major",
      "findings": [
        {
          "id": "f3",
          "description": "Cross-round tracking is specified only at conceptual-group level. The governed review protocol negotiates fixes per reviewer finding, with finding_id preferred and group ID only as fallback, so the draft can lose identity when one group contains multiple findings.",
          "source_section": "<guardrails> / <steps> Step 4"
        },
        {
          "id": "f4",
          "description": "Arbitration identifies the actor and required evidence fields, but the numbered round flow never defines the concrete trigger point that moves a surviving minor disagreement from split-verdict handling into arbitration. That leaves frozen_with_conditions present in <completion> without a fully testable path from <steps>.",
          "source_section": "<guardrails> Arbitration / <steps> Step 4 / <completion> frozen_with_conditions"
        }
      ],
      "redesign_guidance": "Carry unresolved items forward by finding_id whenever available, using finding_group_id only as fallback, and add an explicit arbitration trigger inside the round sequence so frozen_with_conditions is mechanically derivable from review evidence."
    },
    {
      "id": "group-3",
      "summary": "The passed self-check overstates scope deduplication.",
      "severity": "minor",
      "findings": [
        {
          "id": "f5",
          "description": "The compliance claim says scope exclusions were deduplicated into one exclusion list, but the same exclusion set appears twice: under <authority> as 'Does not own' and under <scope> as 'Not in scope'. That makes the pass claim for ARB-006 and ARB-005 unreliable.",
          "source_section": "<authority> Does not own / <scope> Not in scope"
        }
      ],
      "redesign_guidance": "Keep exclusions in one canonical out-of-scope list, move ownership wording to positive scope or authority text, and only mark the self-check passed when the markdown structure actually matches that model."
    }
  ],
  "fix_decisions": [],
  "residual_risks": [
    "Pushback remains narrowly framed around missing authority or missing inputs, so later revisions should keep checking that review rejection states and terminal outcomes stay mechanically distinct.",
    "If per-finding identity is not preserved, repeated rounds can appear to converge while individual findings inside a conceptual group silently drift.",
    "Until the self-check validates its own structural claims against the actual markdown layout, a reported pass cannot be treated as strong governance evidence."
  ],
  "strengths": [
    "Reference evidence is separated from execution inputs instead of being flattened into one undifferentiated list.",
    "Canonical artifacts and run-scoped evidence are mostly separated clearly, with explicit tool-relative paths rooted under the component's role and runs directories.",
    "Context gathering is correctly framed as preconditions outside the numbered execution flow, and the step labels distinguish current required behavior from inherited runtime behavior."
  ]
}

